@prefix cdi: <http://ddialliance.org/Specification/DDI-CDI/1.0/RDF/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/activity-statistical-compilation> ;
            sh:resultMessage "A DDI-CDI Activity may specify cdi:start (xsd:dateTime) for the activity start time" ;
            sh:resultPath cdi:start ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:DatatypeConstraintComponent ;
            sh:sourceShape [ sh:datatype xsd:dateTime ;
                    sh:message "A DDI-CDI Activity may specify cdi:start (xsd:dateTime) for the activity start time" ;
                    sh:path cdi:start ;
                    sh:severity sh:Info ] ;
            sh:value "2025-03-01T09:00:00Z" ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/activity-statistical-compilation> ;
            sh:resultMessage "A DDI-CDI Activity may specify cdi:end (xsd:dateTime) for the activity end time" ;
            sh:resultPath cdi:end ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:DatatypeConstraintComponent ;
            sh:sourceShape [ sh:datatype xsd:dateTime ;
                    sh:message "A DDI-CDI Activity may specify cdi:end (xsd:dateTime) for the activity end time" ;
                    sh:path cdi:end ;
                    sh:severity sh:Info ] ;
            sh:value "2025-06-15T17:00:00Z" ] .
